import * as React from "react";
import PropTypes from "prop-types";
import { graphql } from "gatsby";
import { Helmet } from "react-helmet";
import { useState, useEffect } from "react";
import { Layout } from "../components/common";
import { MetaData } from "../components/common/meta";

/**
 * Single post view (/:slug)
 *
 * This file renders a single post and loads all the content.
 *
 */
const Post = ({ data, location }) => {
    const post = data.ghostPost;
    const [toc, setToc] = useState([]);

    useEffect(() => {
      const parsedHtml = parse(post.html);
      const headers = parsedHtml.filter(element => element.type === 'h1' || element.type === 'h2');
      const tocItems = headers.map((header, index) => ({
        id: `heading-${index}`,
        title: header.props.children[0],
        tagName: header.type
      }));
      setToc(tocItems);
    }, [post.html]);

    return (
        <>
            <MetaData data={data} location={location} type="article" />
            <Helmet>
                <style type="text/css">{`${post.codeinjection_styles}`}</style>                
            </Helmet>
            <Layout>
                <div className="container">
                    <article className="content">
                        {/* {post.feature_image ? (
                            <figure className="post-feature-image">
                                <img
                                    src={post.feature_image}
                                    alt={post.title}
                                />
                            </figure>
                        ) : null} */}
                        <section className="post-full-content">                            
                            <h1 className="content-title">{post.title}</h1>
                            <div className="toc">
                                {toc.map((item, index) => (
                                <a key={index} href={`#${item.id}`} className="toc-link">{item.title}</a>
                                ))}
                            </div>

                            {/* The main post content */}
                            <section
                                className="content-body load-external-scripts"
                                dangerouslySetInnerHTML={{ __html: post.html }}
                            />
                        </section>
                    </article>
                </div>
            </Layout>
        </>
    );
};

Post.propTypes = {
    data: PropTypes.shape({
        ghostPost: PropTypes.shape({
            codeinjection_styles: PropTypes.object,
            title: PropTypes.string.isRequired,
            html: PropTypes.string.isRequired,
            feature_image: PropTypes.string,
        }).isRequired,
    }).isRequired,
    location: PropTypes.object.isRequired,
};

export default Post;

export const postQuery = graphql`
    query ($slug: String!) {
        ghostPost(slug: { eq: $slug }) {
            ...GhostPostFields
        }
    }
`;
